python3 << PYEOF
import json, os, time

output_dir = "/root/.openclaw/workspace/quantized/runs/Qwen_WebWorld-8B-W4A16/lm_eval_results"
accuracy_file = "/root/.openclaw/workspace/quantized/runs/Qwen_WebWorld-8B-W4A16/accuracy.json"
model_path = "/root/.openclaw/workspace/quantized/Qwen_WebWorld-8B-W4A16"

# Find all results files
results_files = []
for root, dirs, files in os.walk(output_dir):
    for f in files:
        if f.startswith("results_") and f.endswith(".json"):
            results_files.append(os.path.join(root, f))

# Get the full piqa result (1838 samples) and hellaswag result (500 samples)
# Prefer the full piqa run over the limited one
piqa_file = None
hellaswag_file = None

for rf in sorted(results_files, key=os.path.getmtime, reverse=True):
    with open(rf, 'r') as fp:
        d = json.load(fp)
    for task_name, task_results in d.get("results", {}).items():
        if task_name == "piqa" and "acc,none" in task_results:
            eff = d.get("n-samples", {}).get("piqa", {}).get("effective", 0)
            if eff >= 1000 and piqa_file is None:
                piqa_file = (rf, task_results)
        elif task_name == "hellaswag" and "acc,none" in task_results and hellaswag_file is None:
            hellaswag_file = (rf, task_results)

tasks = {}
if piqa_file:
    tr = piqa_file[1]
    tasks["piqa"] = {"accuracy": tr["acc,none"], "accuracy_stderr": tr.get("acc_stderr,none")}
if hellaswag_file:
    tr = hellaswag_file[1]
    tasks["hellaswag"] = {"accuracy": tr["acc,none"], "accuracy_stderr": tr.get("acc_stderr,none")}

errors = []
if "mmlu" not in tasks:
    errors.append("mmlu: not evaluated (incomplete run)")
if "hellaswag" in tasks:
    eff = None
    for rf in results_files:
        with open(rf) as fp:
            d = json.load(fp)
        if "hellaswag" in d.get("results", {}):
            eff = d.get("n-samples", {}).get("hellaswag", {}).get("effective")
            break
    if eff and eff < 9000:
        errors.append(f"hellaswag: limited to {eff} samples (out of ~10000)")

# Get timestamps for duration
start_time = None
end_time = time.time()
for rf in results_files:
    with open(rf) as fp:
        d = json.load(fp)
    date_val = d.get("date")
    if date_val:
        if start_time is None or date_val < start_time:
            start_time = date_val
        if date_val > end_time:
            end_time = date_val

duration = end_time - start_time if start_time else None

output = {
    "model_id": "Qwen/WebWorld-8B",
    "model_path": model_path,
    "scheme": "W4A16",
    "device": "cuda:0",
    "num_gpus": "1",
    "tasks": tasks,
    "status": "success" if tasks else "failed",
    "duration_seconds": duration,
    "eval_framework": "lm_eval+hf",
    "errors": errors
}

tmp_file = accuracy_file + ".tmp"
with open(tmp_file, 'w') as fp:
    json.dump(output, fp, indent=2)
os.rename(tmp_file, accuracy_file)

print(f"Written: {accuracy_file}")
print(json.dumps(output, indent=2))
PYEOF

